INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'MU-1', 'mu-1', 'Low Intensity Mixed-Use', 'This district encourages higher density, mixed-use, pedestrian-oriented development in designated growth centers, concentrating diverse housing types with neighborhood-serving commercial and institutional uses.', '3-5 stories with available height bonus', NULL, NULL, NULL, NULL, NULL, NULL, 'Parking for residential uses is clarified in the ordinance.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
